import random

def detect_flakiness(func, n_runs=10):
    results = set()
    for _ in range(n_runs):
        try:
            result = func()
            results.add(result)
        except Exception as e:
            # Normalize exceptions: treat all ValueErrors as one type of failure
            if isinstance(e, ValueError):
                results.add("ValueError_Failure")
            else:
                results.add(type(e).__name__)
    return len(results) > 1

# Test cases provided by the user
def flaky_test():
    return random.choice([True, False])

def always_fails():
    return False

def always_passes():
    return True

def error_flaky():
    if random.random() > 0.5:
        return True
    else:
        raise ValueError("crash")

def stable_error():
    raise ValueError("always crashes")

